(function(){"use strict";var dz=document.getElementById("dropzone");var fi=document.getElementById("fileinput");var fm=document.getElementById("upform");if(!dz||!fi||!fm)return;dz.addEventListener("click",function(){fi.click()});["dragover","dragenter"].forEach(function(ev){dz.addEventListener(ev,function(e){e.preventDefault();dz.classList.add("drag")})});["dragleave","drop"].forEach(function(ev){dz.addEventListener(ev,function(e){e.preventDefault();dz.classList.remove("drag")})});dz.addEventListener("drop",function(e){fi.files=e.dataTransfer.files;fm.submit()})})();